import {
  type ContextSpec,
  type GetterBody,
  type GetterParams,
  type GetterProps,
  GetterPropType,
  type GetterQueryParam,
} from '../types';
import { isNullish, pascal, sortByPriority, stringify } from '../utils';

interface GetPropsOptions {
  body: GetterBody;
  queryParams?: GetterQueryParam;
  params: GetterParams;
  operationName: string;
  headers?: GetterQueryParam;
  context: ContextSpec;
}

export function getProps({
  body,
  queryParams,
  params,
  operationName,
  headers,
  context,
}: GetPropsOptions): GetterProps {
  const bodyProp = {
    name: body.implementation,
    definition: `${body.implementation}${body.isOptional && !context.output.optionsParamRequired ? '?' : ''}: ${body.definition}`,
    implementation: `${body.implementation}${body.isOptional && !context.output.optionsParamRequired ? '?' : ''}: ${body.definition}`,
    default: false,
    required: !body.isOptional || context.output.optionsParamRequired,
    type: GetterPropType.BODY,
  };

  const queryParamsProp = {
    name: 'params',
    definition: getQueryParamDefinition(queryParams, context),
    implementation: getQueryParamDefinition(queryParams, context),
    default: false,
    required: isNullish(queryParams?.isOptional)
      ? !context.output.allParamsOptional || context.output.optionsParamRequired
      : (!queryParams.isOptional && !context.output.allParamsOptional) ||
        context.output.optionsParamRequired,
    type: GetterPropType.QUERY_PARAM,
  };

  const headersProp = {
    name: 'headers',
    definition: `headers${headers?.isOptional && !context.output.optionsParamRequired ? '?' : ''}: ${
      headers?.schema.name
    }`,
    implementation: `headers${headers?.isOptional && !context.output.optionsParamRequired ? '?' : ''}: ${
      headers?.schema.name
    }`,
    default: false,
    required: isNullish(headers?.isOptional)
      ? false
      : !headers.isOptional || context.output.optionsParamRequired,
    type: GetterPropType.HEADER,
  };

  let paramGetterProps: GetterProps;
  if (context.output.override.useNamedParameters && params.length > 0) {
    const parameterTypeName = `${pascal(operationName)}PathParameters`;

    const name = 'pathParams';

    // needs a special model
    const namedParametersTypeDefinition = `export type ${parameterTypeName} = {\n ${params
      .map((property) => property.definition)
      .join(',\n    ')},\n }`;

    const isOptional =
      context.output.optionsParamRequired ||
      params.every((param) => param.default !== undefined);

    const implementation = `{ ${params
      .map(
        (property) =>
          property.default === undefined
            ? property.name
            : `${property.name} = ${stringify(property.default)}`, // if we use property.implementation, we will get `{ version: number = 1 }: ListPetsPathParameters = {}` which isn't valid
      )
      .join(', ')} }: ${parameterTypeName}${isOptional ? ' = {}' : ''}`;

    const destructured = `{ ${params
      .map((property) => property.name)
      .join(', ')} }`;

    paramGetterProps = [
      {
        type: GetterPropType.NAMED_PATH_PARAMS,
        name,
        definition: `${name}: ${parameterTypeName}`,
        implementation,
        default: false,
        destructured,
        required: true,
        schema: {
          name: parameterTypeName,
          model: namedParametersTypeDefinition,
          imports: params.flatMap((property) => property.imports),
        },
      },
    ];
  } else {
    paramGetterProps = params.map((param) => ({
      ...param,
      type: GetterPropType.PARAM,
    }));
  }

  const props = [
    ...paramGetterProps,
    ...(body.definition ? [bodyProp] : []),
    ...(queryParams ? [queryParamsProp] : []),
    ...(headers ? [headersProp] : []),
  ];

  const sortedProps = sortByPriority(props);

  return sortedProps;
}

function getQueryParamDefinition(
  queryParams: GetterQueryParam | undefined,
  context: ContextSpec,
): string {
  const paramType = queryParams?.schema.name;
  return `params${(queryParams?.isOptional || context.output.allParamsOptional) && !context.output.optionsParamRequired ? '?' : ''}: ${paramType}`;
}
